import { defineConfig } from "@playwright/test";

export default defineConfig({
  testDir: "./tests/e2e",
  fullyParallel: true,
  retries: 0,
  reporter: "list",
  use: {
    baseURL: "http://127.0.0.1:3100",
    trace: "on-first-retry"
  },
  webServer: {
    command: "npm run dev -- --hostname 127.0.0.1 --port 3100",
    url: "http://127.0.0.1:3100/api/health",
    reuseExistingServer: !process.env.CI,
    timeout: 120000
  }
});

import { mkdirSync, createWriteStream, existsSync } from "node:fs";
import path from "node:path";
import { spawn } from "node:child_process";

const npmBin = process.platform === "win32" ? "npm.cmd" : "npm";
const logsDir = path.resolve("logs");
const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
const logFile = path.join(logsDir, `server-${timestamp}.log`);
const port = process.env.PORT ?? "3000";

mkdirSync(logsDir, { recursive: true });

const prepare = spawn(npmBin, ["run", "db:prepare"], {
  cwd: process.cwd(),
  stdio: "inherit",
  env: process.env
});

const prepareCode = await new Promise((resolve) => {
  prepare.on("exit", (code) => resolve(code ?? 1));
});

if (prepareCode !== 0) {
  process.exit(prepareCode);
}

if (!existsSync(path.resolve(".next", "BUILD_ID"))) {
  const build = spawn(npmBin, ["run", "build"], {
    cwd: process.cwd(),
    stdio: "inherit",
    env: process.env
  });

  const buildCode = await new Promise((resolve) => {
    build.on("exit", (code) => resolve(code ?? 1));
  });

  if (buildCode !== 0) {
    process.exit(buildCode);
  }
}

const stream = createWriteStream(logFile, { flags: "a" });
const child = spawn(npmBin, ["run", "start", "--", "--hostname", "127.0.0.1", "--port", port], {
  cwd: process.cwd(),
  env: process.env
});

child.stdout.pipe(process.stdout);
child.stderr.pipe(process.stderr);
child.stdout.pipe(stream);
child.stderr.pipe(stream);

console.log(`Server logs: ${logFile}`);
console.log(`LOG_LEVEL=${process.env.LOG_LEVEL ?? "info"}`);

child.on("exit", (code) => {
  stream.end();
  process.exit(code ?? 0);
});

import { existsSync } from "node:fs";
import { spawn } from "node:child_process";

const port = process.env.SMOKE_PORT ?? "3200";
const host = "127.0.0.1";
const npmBin = process.platform === "win32" ? "npm.cmd" : "npm";

function run(command, args) {
  return new Promise((resolve, reject) => {
    const child = spawn(command, args, {
      cwd: process.cwd(),
      stdio: "inherit",
      env: process.env
    });

    child.on("exit", (code) => {
      if (code === 0) {
        resolve();
        return;
      }
      reject(new Error(`${command} ${args.join(" ")} failed with exit code ${code ?? "unknown"}`));
    });
  });
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function waitForHealth(url) {
  for (let attempt = 0; attempt < 60; attempt += 1) {
    try {
      const response = await fetch(url);
      if (response.ok) {
        return;
      }
    } catch {
      // Keep polling until the server is ready.
    }
    await sleep(1000);
  }
  throw new Error(`Timed out waiting for ${url}`);
}

await run(npmBin, ["run", "db:prepare"]);

if (!existsSync(".next/BUILD_ID")) {
  await run(npmBin, ["run", "build"]);
}

const child = spawn(npmBin, ["run", "start", "--", "--hostname", host, "--port", port], {
  cwd: process.cwd(),
  stdio: "inherit",
  env: {
    ...process.env,
    PORT: port
  }
});

try {
  await waitForHealth(`http://${host}:${port}/api/health`);
} finally {
  child.kill("SIGTERM");
}
